   407 | // Try to collect variable and constant offsets for \p GEP, partly traversing
   408 | // nested GEPs. Returns an OffsetResult with nullptr as BasePtr of collecting
   409 | // the offset fails.
   410 | static OffsetResult collectOffsets(GEPOperator &GEP, const DataLayout &DL) {
   411 |   OffsetResult Result(GEP, DL);
   412 |   unsigned BitWidth = Result.ConstantOffset.getBitWidth();
