   423 |         DL, BitWidth, VariableOffsets2, ConstantOffset2);
   424 |     // TODO: Support cases with more than 1 variable offset.
   425 |     if (!CanCollectInner || Result.VariableOffsets.size() > 1 ||
   426 |         VariableOffsets2.size() > 1 ||
   427 |         (Result.VariableOffsets.size() >= 1 && VariableOffsets2.size() >= 1)) {
   428 |       // More than 1 variable index, use outer result.
   429 |       return Result;
   430 |     }
   431 |     Result.BasePtr = InnerGEP->getPointerOperand();
   432 |     Result.ConstantOffset += ConstantOffset2;
